class Solution {
    public int numSub(String s) {
        long count = 0;
        int mod = 1000000007;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') {
                long currentCount = 1;
                for (int j = i + 1; j < s.length(); j++) {
                    if (s.charAt(j) == '1') {
                        currentCount++;
                        count = (count + currentCount) % mod;
                    } else {
                        break;
                    }
                }
            }
        }
        return (int) count;
    }
}
